import json
import re

# Load the data - check if we need to read from files
reviews_var = locals()['var_functions.query_db:16']
businesses_var = locals()['var_functions.query_db:18']

# Read data if needed
if isinstance(reviews_var, str) and '.json' in reviews_var:
    with open(reviews_var) as f:
        reviews = json.load(f)
else:
    reviews = reviews_var

if isinstance(businesses_var, str) and '.json' in businesses_var:
    with open(businesses_var) as f:
        businesses = json.load(f)
else:
    businesses = businesses_var

# Build business map
business_map = {}
for b in businesses:
    bid = b['business_id']
    m = re.search(r'(\d+)$', bid)
    if m:
        business_map[m.group(1)] = b

# Count categories
category_counts = {}

for r in reviews:
    # Get business numeric ID
    bref = r['business_ref']
    m = re.search(r'(\d+)$', bref)
    if not m:
        continue

    bnum = m.group(1)
    if bnum not in business_map:
        continue

    biz = business_map[bnum]
    desc = biz.get('description', '')

    # Extract categories - look for common patterns
    if 'services in' in desc:
        idx1 = desc.lower().find('services in') + 11
        idx2 = desc.find('.', idx1)
        if idx2 == -1:
            idx2 = len(desc)
        cats = desc[idx1:idx2]

        # Split categories
        parts = cats.split(',')
        for part in parts:
            part = part.strip().rstrip('.')
            if 'and ' in part:
                subparts = part.split(' and ')
                for sp in subparts:
                    sp = sp.strip()
                    if len(sp) > 2 and sp != 'and more':
                        category_counts[sp] = category_counts.get(sp, 0) + 1
            elif len(part) > 2 and part != 'and more':
                category_counts[part] = category_counts.get(part, 0) + 1

# Get top 5
top5 = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)[:5]

# Format output
output = []
for cat, count in top5:
    if cat:
        output.append((cat, count))

data = {'top_categories': output, 'total_reviews': len(reviews)}

print('__RESULT__:')
print(json.dumps(data))

