import json
import re

# Load data
reviews_var = locals()['var_functions.query_db:16']
businesses_var = locals()['var_functions.query_db:18']

if isinstance(reviews_var, str) and '.json' in reviews_var:
    with open(reviews_var) as f:
        reviews = json.load(f)
else:
    reviews = reviews_var

if isinstance(businesses_var, str) and '.json' in businesses_var:
    with open(businesses_var) as f:
        businesses = json.load(f)
else:
    businesses = businesses_var

# Build business map
business_map = {}
for b in businesses:
    bid = b['business_id']
    m = re.search(r'(\d+)$', bid)
    if m:
        business_map[m.group(1)] = b

# Count categories
category_counts = {}
processed = 0

for r in reviews:
    bref = r['business_ref']
    m = re.search(r'(\d+)$', bref)
    if not m:
        continue

    bnum = m.group(1)
    if bnum not in business_map:
        continue

    biz = business_map[bnum]
    desc = biz.get('description', '')

    # Better category extraction
    categories = []

    # Pattern 1: "services in X, Y, and Z."
    if 'services in' in desc:
        # Find the text after 'services in' and before the next period
        start = desc.lower().find('services in') + 11
        end = desc.find('.', start)
        if end > start:
            cats_text = desc[start:end]
            # Split by comma and extract categories
            parts = cats_text.split(',')
            for part in parts:
                part = part.strip()
                # Clean up 'and' prefix
                if part.startswith('and '):
                    part = part[4:]
                # Remove trailing 'and'
                if part.endswith(' and'):
                    part = part[:-4]
                part = part.rstrip('. ')
                if part and len(part) > 2 and part not in ['and more', 'services']:
                    categories.append(part)

    # Pattern 2: "including X, Y, and Z."
    if not categories and 'including' in desc:
        start = desc.lower().find('including') + 9
        end = desc.find('.', start)
        if end > start:
            cats_text = desc[start:end]
            # Split by comma and 'and'
            if ', and' in cats_text:
                # Handle Oxford comma
                main_parts = cats_text.split(', and')
                for i, part in enumerate(main_parts):
                    if i == len(main_parts) - 1:
                        # Last part may have multiple items
                        subparts = part.split(',')
                        for sp in subparts:
                            sp = sp.strip().rstrip('. ')
                            if sp and len(sp) > 2:
                                categories.append(sp)
                    else:
                        part = part.strip().rstrip('. ')
                        if part and len(part) > 2:
                            categories.append(part)
            else:
                # Simple split by commas
                parts = cats_text.split(',')
                for part in parts:
                    part = part.strip().rstrip('. ')
                    if part and len(part) > 2:
                        categories.append(part)

    # Pattern 3: "in X, Y, and Z." at the end
    if not categories:
        # Look for "in " followed by capitalized words at the end
        end_match = re.search(r'(?:in|of)\s+((?:[A-Z][^,\.]+(?:,\s*)?)+(?:and\s*)?[A-Z][^,\.]+)\.$', desc)
        if end_match:
            cats_text = end_match.group(1)
            parts = re.split(r',\s*|\s+and\s+', cats_text)
            for part in parts:
                part = part.strip()
                if part and len(part) > 2 and part not in ['and more', 'services']:
                    categories.append(part)

    # Count valid categories
    if categories:
        for cat in categories:
            # Clean up category names
            cat = cat.strip()
            if cat:
                category_counts[cat] = category_counts.get(cat, 0) + 1
        processed += 1

# Get top 5 categories
top5 = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)[:5]

print('Results:')
print(f'Processed {len(reviews)} reviews')
print(f'Successfully categorized {processed} reviews')
print('Top 5 categories:')
for i, (cat, count) in enumerate(top5, 1):
    print(f'{i}. {cat}: {count} reviews')

# Prepare output
result = {
    'top_5_categories': top5,
    'total_reviews': len(reviews),
    'categorized_reviews': processed
}

print('__RESULT__:')
print(json.dumps(result))

