import json
import re
from collections import defaultdict

# Load data
reviews = locals()['var_functions.query_db:16']
businesses = locals()['var_functions.query_db:52']

# Check and load from files if needed
if isinstance(reviews, str) and reviews.endswith('.json'):
    with open(reviews) as f:
        reviews = json.load(f)
if isinstance(businesses, str) and businesses.endswith('.json'):
    with open(businesses) as f:
        businesses = json.load(f)

# Build business map
business_map = {}
for biz in businesses:
    biz_id = biz['business_id']
    m = re.search(r'(\d+)$', biz_id)
    if m:
        num_id = m.group(1)
        business_map[num_id] = biz

# Process reviews and count categories
category_counts = defaultdict(int)
processed = 0

for review in reviews:
    # Get business reference
    bref = review['business_ref']
    m = re.search(r'(\d+)$', bref)
    if not m:
        continue

    bnum = m.group(1)
    if bnum not in business_map:
        continue

    biz = business_map[bnum]
    desc = biz.get('description', '')
    if not desc:
        continue

    # Extract categories
    categories = []
    desc_lower = desc.lower()

    # Try different patterns
    if 'services in' in desc_lower:
        start = desc_lower.find('services in') + 11
        end = desc.find('.', start)
        if end == -1:
            end = len(desc)
        cat_text = desc[start:end]
        categories = [c.strip().rstrip('. ') for c in cat_text.split(',')]
    elif 'including' in desc_lower:
        start = desc_lower.find('including') + 9
        end = desc.find('.', start)
        if end == -1:
            end = len(desc)
        cat_text = desc[start:end]
        categories = [c.strip().rstrip('. ') for c in cat_text.split(',')]

    # Count valid categories
    for cat in categories:
        if cat and len(cat) > 2 and cat != 'and more':
            category_counts[cat] += 1
            processed += 1

# Get top 5
top5 = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)[:5]

# Prepare result
result = {
    'top_5_categories': top5,
    'total_reviews': len(reviews),
    'processed_reviews': processed
}

print('__RESULT__:')
print(json.dumps(result, indent=2))

